CREATE VIEW `dim_short_video_mapping_view` (`id` COMMENT "主键", `rights_holder_id` COMMENT "版权方id,海剧或者国剧视频不归属这个版权方，该数据自动无效", `source_series_id` COMMENT "海剧视频id", `cn_source_series_id` COMMENT "国剧视频id", `create_user_info` COMMENT "创建人", `update_user_info` COMMENT "修改人", `create_time` COMMENT "创建时间", `update_time` COMMENT "更新时间", `is_delete` COMMENT "是否删除", `sr_createtime` COMMENT "sr入库时间", `sr_updatetime` COMMENT "sr更新时间")
COMMENT "国剧海剧映射表" AS SELECT `ods`.`ods_tidb_short_video_admin_video_mapping`.`Id`, `ods`.`ods_tidb_short_video_admin_video_mapping`.`RightsHolderId`, `ods`.`ods_tidb_short_video_admin_video_mapping`.`SourceSeriesId`, `ods`.`ods_tidb_short_video_admin_video_mapping`.`CnSourceSeriesId`, `ods`.`ods_tidb_short_video_admin_video_mapping`.`CreateUserInfo`, `ods`.`ods_tidb_short_video_admin_video_mapping`.`UpdateUserInfo`, `ods`.`ods_tidb_short_video_admin_video_mapping`.`CreateTime`, `ods`.`ods_tidb_short_video_admin_video_mapping`.`UpdateTime`, `ods`.`ods_tidb_short_video_admin_video_mapping`.`IsDelete`, `ods`.`ods_tidb_short_video_admin_video_mapping`.`sr_createtime`, `ods`.`ods_tidb_short_video_admin_video_mapping`.`sr_updatetime`
FROM `ods`.`ods_tidb_short_video_admin_video_mapping`;
